package be.schaubroeck.lpb.rkm.rekenmotor.rsz.werkbonus.basisbedrag;

import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import lombok.AllArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;

import java.math.BigDecimal;

@Slf4j
@AllArgsConstructor
public class WerkbonusBasisBedragVanaf2008 implements WerkbonusBasisBedrag {

    private final Money forfaitairBedrag1;
    private final Money forfaitairBedrag2;
    private final Money grensBedragS0;
    private final Money grensBedragS1;
    private final Money grensBedragS2;
    private final BigDecimal alpha1;
    private final BigDecimal alpha2;

    public WerkbonusBasisBedragVanaf2008(ConstantManager constantManager, LocalDate selectieDatum) {
        this.forfaitairBedrag1 = constantManager.getByCodeDatum(Konstanten.KST_LL_FORFAIT, selectieDatum).getMoney();
        this.forfaitairBedrag2 = constantManager.getByCodeDatum(Konstanten.KST_LL_FORFAIT1, selectieDatum).getMoney();
        this.grensBedragS0 = constantManager.getByCodeDatum(Konstanten.KST_LL_S0, selectieDatum).getMoney();
        this.grensBedragS1 = constantManager.getByCodeDatum(Konstanten.KST_LL_S1, selectieDatum).getMoney();
        this.grensBedragS2 = constantManager.getByCodeDatum(Konstanten.KST_LL_S2, selectieDatum).getMoney();
        this.alpha1 = constantManager.getByCodeDatum(Konstanten.KST_LL_A, selectieDatum).getBigDecimal();
        this.alpha2 = constantManager.getByCodeDatum(Konstanten.KST_LL_A1, selectieDatum).getBigDecimal();
    }

    public Money bereken(Money referentieLoon) {
        Money basisBedrag;
        if (referentieLoon.compareTo(grensBedragS0) <= 0) {
            basisBedrag = forfaitairBedrag2;
            log.debug("referentieLoon<=grensBedragS0:{}<={}", referentieLoon, grensBedragS0);
        } else if (referentieLoon.compareTo(grensBedragS1) <= 0) {
            basisBedrag = forfaitairBedrag2.subtract(referentieLoon.subtract(grensBedragS0).multiply(alpha2));
            log.debug("grensBedragS0<referentieLoon<=grensBedragS1:{}<{}<={}", grensBedragS0, referentieLoon, grensBedragS1);
        } else if (referentieLoon.compareTo(grensBedragS2) <= 0) {
            basisBedrag = forfaitairBedrag1.subtract(referentieLoon.subtract(grensBedragS0).multiply(alpha1));
            log.debug("grensBedragS1<referentieLoon<=grensBedragS2:{}<{}<={}", grensBedragS1, referentieLoon, grensBedragS2);
        } else {
            basisBedrag = Money.ZERO;
            log.debug("referentieLoon>grensBedragS2:{}>{}", referentieLoon, grensBedragS2);
            log.debug("basisBedrag=ZERO:");
        }
        log.debug("basisBedrag:{}", basisBedrag);
        return basisBedrag.round(2);
    }

    @Override
    public Money getBegrenstForfait() {
        return forfaitairBedrag2;
    }
}
